import numpy as np
from time import time

def primeFactorizationSum(n):
	num = n
	total = 0
	if num % 2 == 0:
		count = 0
		while num % 2 == 0:
			num //= 2
			count += 1
		total += count * 2
	i = 3
	while i * i <= num:
		if num % i == 0:
			count = 0
			while num % i == 0:
				num //= i
				count += 1
			total += count * i
		i += 2
	if num > 1:
		total += num
	return total

n = 1_000_000
A = np.empty(n - 1, dtype=np.int64)

start = time()

for i in range(0, n - 1):
	A[i] = primeFactorizationSum(i + 2)

end = time()

print(f"Primes sum array: {A}")
print(f"Execution in {round(end - start, 6)} s")
```

