On GPU, using CuPy and a custom raw kernel:

```{.python}
import cupy as cp

# Define the CUDA kernel — each GPU thread handles one number
primeFactorizationSum_kernel = cp.RawKernel(
	r"""
extern "C" __global__
void primeFactorizationSum(long long* A, int n) {
	int idx = blockDim.x * blockIdx.x + threadIdx.x;
	if (idx >= n) return;

	long long num = idx + 2;  // numbers 2..n
	long long total = 0;

	if (num % 2 == 0) {
		int count = 0;
		while (num % 2 == 0) { num /= 2; count++; }
		total += count * 2;
	}
	for (long long i = 3; i * i <= num; i += 2) {
		if (num % i == 0) {
			int count = 0;
			while (num % i == 0) { num /= i; count++; }
			total += count * i;
		}
	}
	if (num > 1) total += num;

	A[idx] = total;
}
""",
	"primeFactorizationSum",
)

n = 1_000_000
B = cp.empty(n - 1, dtype=cp.int64)

# Set the number of threads per block
threads = 256

# Set the number of blocks per grid
blocks = (n - 1 + threads - 1) // threads

print(f"Primes sum array: {B}")
```

Now let's benchmark the code and print the result:

```{.python}
from cupyx.profiler import benchmark

print(
	benchmark(
        primeFactorizationSum_kernel, ((blocks,), (threads,), (B, n - 1)), n_repeat=20
	)
)

print(f"Primes sum array: {A}")
```

